const fs = require('fs');
const path = require('path');
const { compile } = require('json-schema-to-typescript');

async function main() {
  const schemasDir = path.resolve(__dirname, '../../realtime-schemas');
  const outputFilePath = path.resolve(__dirname, '../src/contracts/realtime.ts');
  const zodOutputFilePath = path.resolve(__dirname, '../src/contracts/realtime.schemas.ts');

  const files = fs.readdirSync(schemasDir).filter((f) => f.endsWith('.json'));

  const declaredTypes = new Set();
  const zodSchemas = [];
  let typescriptContent =
    '/* eslint-disable */\n// Generated by scripts/generate-realtime-contracts.cjs. Do not edit.\n\n';

  for (const file of files) {
    const filePath = path.join(schemasDir, file);
    const schemaContent = JSON.parse(fs.readFileSync(filePath, 'utf-8'));

    const typeName = path.basename(file, '.json');
    const ts = await compile(schemaContent, typeName, {
      bannerComment: '',
      style: {
        singleQuote: true,
      },
    });

    const lines = ts.split('\n');
    let currentBlock = [];
    let currentTypeName = null;
    let inBlock = false;

    for (const line of lines) {
      const match = line.match(/^export (type|interface) (\w+)/);
      if (match) {
        if (currentBlock.length > 0 && currentTypeName) {
          if (!declaredTypes.has(currentTypeName)) {
            declaredTypes.add(currentTypeName);
            typescriptContent += currentBlock.join('\n') + '\n\n';
          }
        }
        currentBlock = [line];
        currentTypeName = match[2];
        inBlock = true;
      } else {
        if (inBlock) {
          currentBlock.push(line);
          const trimmed = line.trim();
          if (trimmed === '}' || (!line.startsWith(' ') && trimmed === '')) {
            if (!declaredTypes.has(currentTypeName)) {
              declaredTypes.add(currentTypeName);
              typescriptContent += currentBlock.join('\n') + '\n\n';
            }
            currentBlock = [];
            currentTypeName = null;
            inBlock = false;
          }
        } else {
          if (line.trim()) {
            typescriptContent += line + '\n';
          }
        }
      }
    }
    if (currentBlock.length > 0 && currentTypeName) {
      if (!declaredTypes.has(currentTypeName)) {
        declaredTypes.add(currentTypeName);
        typescriptContent += currentBlock.join('\n') + '\n\n';
      }
    }

    zodSchemas.push({ typeName, schemaContent });
  }

  fs.mkdirSync(path.dirname(outputFilePath), { recursive: true });
  fs.writeFileSync(outputFilePath, typescriptContent, 'utf-8');
  fs.writeFileSync(zodOutputFilePath, buildZodContent(zodSchemas), 'utf-8');
  console.log(`Successfully generated realtime contracts to ${outputFilePath}`);
}

function buildZodContent(schemas) {
  const lines = [
    "import { z } from 'zod';",
    '',
    '// Generated by scripts/generate-realtime-contracts.cjs. Do not edit.',
    '',
  ];

  for (const { typeName, schemaContent } of schemas) {
    const defs = schemaContent.$defs ?? {};
    for (const [defName, defSchema] of Object.entries(defs)) {
      lines.push(
        `export const ${typeName}${defName}Schema = ${schemaToZod(defSchema, typeName)};`,
        '',
      );
    }
    lines.push(`export const ${typeName}Schema = ${schemaToZod(schemaContent, typeName)};`, '');
  }

  lines.push('export const realtimeSchemas = {');
  for (const { typeName } of schemas) {
    lines.push(`  ${typeName}: ${typeName}Schema,`);
  }
  lines.push('} as const;');
  return `${lines.join('\n')}\n`;
}

function schemaToZod(schema, ownerTypeName) {
  if (schema.$ref) {
    const refName = schema.$ref.split('/').pop();
    return `z.lazy(() => ${ownerTypeName}${refName}Schema)`;
  }
  if (schema.const !== undefined) {
    return `z.literal(${JSON.stringify(schema.const)})`;
  }
  if (schema.enum) {
    return `z.enum(${JSON.stringify(schema.enum)} as const)`;
  }
  if (schema.anyOf) {
    return `z.union([${schema.anyOf.map((item) => schemaToZod(item, ownerTypeName)).join(', ')}])`;
  }
  if (schema.type === 'object') {
    const properties = Object.entries(schema.properties ?? {}).map(([name, property]) => {
      const required = schema.required?.includes(name) ?? false;
      const value = schemaToZod(property, ownerTypeName);
      return `    ${JSON.stringify(name)}: ${required ? value : `${value}.optional()`},`;
    });
    if (schema.additionalProperties && typeof schema.additionalProperties === 'object') {
      const value = schemaToZod(schema.additionalProperties, ownerTypeName);
      return `z.record(z.string(), ${value})`;
    }
    if (schema.additionalProperties === true) {
      return 'z.record(z.string(), z.unknown())';
    }
    return `z.object({\n${properties.join('\n')}\n  }).passthrough()`;
  }
  if (schema.type === 'array') {
    return `z.array(${schemaToZod(schema.items ?? {}, ownerTypeName)})`;
  }
  if (schema.type === 'string') {
    if (schema.format === 'uuid') return 'z.string().uuid()';
    if (schema.format === 'date-time') return 'z.string().datetime({ offset: true })';
    return 'z.string()';
  }
  if (schema.type === 'integer') return 'z.number().int()';
  if (schema.type === 'number') return 'z.number()';
  if (schema.type === 'boolean') return 'z.boolean()';
  if (schema.type === 'null') return 'z.null()';
  return 'z.unknown()';
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
